const rows = $input.all().map(i => i.json);
const materias = [...new Set(rows.flatMap(r => (r.especialidad_materias||'').split(',').map(m => m.trim()).filter(Boolean)))];
const keyboard = materias.map(m => [{ text: m, callback_data: 'MAT_' + m }]);
const prep = $('Preparar Datos').first().json;
return [{ json: { chat_id: prep.chat_id, keyboard } }];

const prep = $('Preparar Datos').first().json;
const rows = $input.all().map(i => i.json);
let texto = 'No tienes tutorias registradas.';
if (rows.length) {
  texto = rows.map(r => `Materia: ${r.materia}\nFecha: ${r.fecha} ${r.hora}\nEstado: ${r.estado}`).join('\n\n');
}
return [{ json: { chat_id: prep.chat_id, texto } }];

const j = $input.first().json;
const texto = (j.entrada || '').trim();
const regex = /^\d{4}-\d{2}-\d{2}$/;
const fechaValida = regex.test(texto) && !isNaN(Date.parse(texto));
const dias = ['Domingo','Lunes','Martes','Miercoles','Jueves','Viernes','Sabado'];
const dia_semana = fechaValida ? dias[new Date(texto + 'T00:00:00').getDay()] : '';
return [{ json: { ...j, fecha: texto, fechaValida, dia_semana } }];

